#ifndef XPCOMComponent_h_
#define XPCOMComponent_h_

#include "nsIObserverService.h"
#include "nsISupports.h"

// {A1B2C3D4-E5F6-47A8-B9C0-D1E2F3A4B5C6}
#define NS_XPCOMCOMPONENT_CID \
  {0xa1b2c3d4, 0xe5f6, 0x47a8, {0xb9, 0xc0, 0xd1, 0xe2, 0xf3, 0xa4, 0xb5, 0xc6}}

/**
 * Example XPCOM component implementing nsIObserverService interface.
 * Demonstrates proper use of XPCOM reference counting and component
 * registration patterns.
 */
class XPCOMComponent final : public nsIObserverService {
 public:
  NS_DECL_ISUPPORTS
  NS_DECL_NSIOBSERVERSERVICE

  XPCOMComponent();

  /**
   * Factory constructor called by the component manager.
   */
  [[nodiscard]] static nsresult Create(const nsIID& aIID, void** aInstancePtr);

 private:
  ~XPCOMComponent();
};

#endif /* XPCOMComponent_h_ */

/* -*- Mode: C++; tab-width: 8; indent-tabs-mode: nil; c-basic-offset: 2 -*- */
/* vim: set ts=8 sts=2 et sw=2 tw=80: */
