// - AddRef: increments reference count
// - Release: decrements reference count and deletes object when count reaches zero
NS_IMPL_ISUPPORTS(XPCOMComponent, nsIObserverService)

XPCOMComponent::XPCOMComponent() {
  LOG(("XPCOMComponent::XPCOMComponent()"));
}

